// ============================================================
// WF-10: CRON CIERRE AUTOMATICO HANDOFF
// Se ejecuta cada 10 minutos.
// Busca conversaciones con handoff_humano=true que lleven
// mas de 2 horas sin actividad (updated_at).
// Para cada una:
//   - Cierra el handoff (handoff_humano=false, estado=menu_principal/inicio)
//   - Notifica al paciente por WhatsApp con despedida + mini guia
//   - Notifica a la secretaria por Telegram con el aviso minimo
// ============================================================

const helpers = this.helpers;
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
const WA_TOKEN = $env.META_WHATSAPP_TOKEN;
const PHONE_ID = '963190063548521';
const TELEGRAM_TOKEN = $env.TELEGRAM_BOT_TOKEN || '';
const TELEGRAM_CHAT_SECRETARIA = '6343825256'; // Demo: Carlos. En prod: env var.

const INACTIVIDAD_HS = 2;
const INACTIVIDAD_MS = INACTIVIDAD_HS * 60 * 60 * 1000;

// ── Supabase helpers ──
async function supaGet(t, p) {
  try {
    return await helpers.httpRequest({
      method: 'GET',
      url: `${SUPABASE_URL}/rest/v1/${t}`,
      qs: p || {},
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
    });
  } catch (e) { return []; }
}
async function supaUpdate(t, f, d) {
  try {
    await helpers.httpRequest({
      method: 'PATCH',
      url: `${SUPABASE_URL}/rest/v1/${t}`,
      qs: f,
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ ...d, updated_at: new Date().toISOString() })
    });
  } catch (e) {}
}

// ── WhatsApp helpers ──
async function sendText(phone, text) {
  try {
    await helpers.httpRequest({
      method: 'POST',
      url: `https://graph.facebook.com/v21.0/${PHONE_ID}/messages`,
      headers: { 'Authorization': `Bearer ${WA_TOKEN}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ messaging_product: 'whatsapp', to: phone, type: 'text', text: { body: text } })
    });
  } catch (e) {}
}
async function sendButtons(phone, text, buttons) {
  try {
    await helpers.httpRequest({
      method: 'POST',
      url: `https://graph.facebook.com/v21.0/${PHONE_ID}/messages`,
      headers: { 'Authorization': `Bearer ${WA_TOKEN}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        messaging_product: 'whatsapp',
        to: phone,
        type: 'interactive',
        interactive: {
          type: 'button',
          body: { text },
          action: {
            buttons: buttons.slice(0, 3).map(b => ({
              type: 'reply',
              reply: { id: b.id, title: b.title.substring(0, 20) }
            }))
          }
        }
      })
    });
  } catch (e) {}
}

// ── Telegram helper ──
async function sendTelegram(chatId, text) {
  if (!TELEGRAM_TOKEN) return;
  try {
    await helpers.httpRequest({
      method: 'POST',
      url: `https://api.telegram.org/bot${TELEGRAM_TOKEN}/sendMessage`,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ chat_id: chatId, text, parse_mode: 'HTML' })
    });
  } catch (e) {}
}

// ============================================================
// EJECUCION PRINCIPAL
// ============================================================

const cutoff = new Date(Date.now() - INACTIVIDAD_MS).toISOString();

// Buscar conversaciones en handoff con updated_at mas viejo que el cutoff
const stale = await supaGet('consultorio_conversaciones', {
  handoff_humano: 'eq.true',
  updated_at: `lt.${cutoff}`,
  select: 'id,telefono_wa,contexto,updated_at'
});

if (!stale || !stale.length) {
  return [{ json: { action: 'no_stale_handoffs', checked_at: new Date().toISOString() } }];
}

const cerrados = [];

for (const conv of stale) {
  const phone = conv.telefono_wa;
  const ctxOriginal = conv.contexto || {};
  const nombreCompleto = ctxOriginal.pacienteNombre || '';
  const primerNombre = nombreCompleto ? nombreCompleto.split(' ')[0] : '';
  const tieneFicha = !!ctxOriginal.pacienteId;

  // Limpiar contexto: sacar estado residual del handoff
  const ctxLimpio = { ...ctxOriginal };
  delete ctxLimpio.handoffResumen;
  delete ctxLimpio.retry_count;
  delete ctxLimpio.last_failed_state;

  // Estado destino: si ya tiene ficha, menu_principal. Si no, inicio.
  const estadoDestino = tieneFicha ? 'menu_principal' : 'inicio';

  // Cerrar handoff
  await supaUpdate(
    'consultorio_conversaciones',
    { id: `eq.${conv.id}` },
    {
      handoff_humano: false,
      estado: estadoDestino,
      contexto: ctxLimpio
    }
  );

  // ── Notificar al paciente (cierre + despedida + mini guia) ──
  const saludo = primerNombre ? `Hola ${primerNombre}` : 'Hola';

  if (tieneFicha) {
    // Paciente con ficha: mandar menu principal directo
    const cuerpo =
      `${saludo}, pasaron ${INACTIVIDAD_HS} horas sin actividad, asi que cerramos el chat con la secretaria. 👋\n\n` +
      `Ya podes volver a usar el asistente virtual cuando quieras.\n\n` +
      `📌 *Como volver a comunicarte*\n` +
      `• Escribi *"hola"* para empezar de nuevo\n` +
      `• Tocá un botón de abajo para ir directo\n` +
      `• Escribi *"recepción"* si queres hablar con una persona\n\n` +
      `¿En que te puedo ayudar?`;

    await sendButtons(phone, cuerpo, [
      { id: 'menu_turno',     title: 'Sacar turno' },
      { id: 'menu_cancelar',  title: 'Cancelar/Cambiar' },
      { id: 'menu_consultar', title: 'Mi proximo turno' }
    ]);
  } else {
    // Paciente sin ficha completa: mensaje de cierre + guia para reiniciar
    const cuerpo =
      `${saludo}, pasaron ${INACTIVIDAD_HS} horas sin actividad, asi que cerramos el chat con la secretaria. 👋\n\n` +
      `📌 *Como volver a comunicarte*\n` +
      `• Escribi *"hola"* en cualquier momento y el asistente te va a guiar\n` +
      `• Si preferis hablar con una persona, escribi *"recepción"*\n\n` +
      `¡Que tengas buen dia!`;

    await sendText(phone, cuerpo);
  }

  // ── Notificar a la secretaria (aviso minimo) ──
  await sendTelegram(TELEGRAM_CHAT_SECRETARIA, 'Este chat se cerró por inactividad');

  cerrados.push({ phone, nombre: nombreCompleto, updated_at: conv.updated_at });
}

return [{
  json: {
    action: 'handoffs_cerrados',
    total: cerrados.length,
    cerrados,
    checked_at: new Date().toISOString()
  }
}];

